head.script:
scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.lobranCd = $c.data.getMemInfo("loUpperLobranCd"); //  물류상위점소코드

/*전역변수*/
scwin.hid_chklineCd = "";  //LINE
scwin.hid_chkcvssl = "";   //본선
scwin.hid_chklineNm = "";
scwin.hid_chkcvsslNm = "";

scwin.onpageload = function () {

    scwin._isInitLobran = true;

    // 0년, 0개월, -7일 계산
    let sevenDaysAgoWithComf = WebSquare.date.dateAdd(scwin.strCurDate, -30);
    udc_fromToCalendar.setInitDate(sevenDaysAgoWithComf, scwin.strCurDate); //udc달력 형식

    //공통코드 적용()  // compID: "acb_co_lc_nextOdrKind" 
    const codeOptions = [
        { grpCd: "SD113" },
        { grpCd: "SD104", compID: "acb_lc_crryInOutClsCd" }
    ];

    $c.data.setCommonCode(codeOptions);


    // 화면 진입 시 기본 비활성
    acb_lc_oldpireCd.setValue("");
    acb_lc_oldpireCd.setDisabled(true);

    grp_totalCnt.setStyle("display", "none");
    total.setValue("");

    // 메모리 점소값 기준으로도 1차 반영
    scwin.setOldPierState(scwin.lobranCd);

    //점소콤보 조회
    $c.sbm.execute(sbm_lobran);
};

scwin._nextOdrInitDone = false;

//공통(최종오더 값중에서 fillter 사용)
scwin.ondataload = function () {

    if (scwin._nextOdrInitDone) return;
    scwin._nextOdrInitDone = true;

    scwin.setNextOdrKind();
};

scwin.setNextOdrKind = function () {
    try {
        let dlt = $c.data.getCommonCodeDataList("SD113");
        console.log("[NextOdr] commonCodeDataList =", dlt);

        if (!dlt) {
            console.log("[NextOdr] SD113 공통코드 DataList 없음");
            return;
        }


        let arr = [];
        let rowCount = dlt.getRowCount ? dlt.getRowCount() : 0;

        for (let i = 0; i < rowCount; i++) {
            let code = String(dlt.getCellData(i, "cd") || "").trim();
            let name = String(dlt.getCellData(i, "cdNm") || "").trim();
            let fltrCd1 = String(dlt.getCellData(i, "fltrCd1") || "").trim();
            let fltrCd3 = String(dlt.getCellData(i, "fltrCd3") || "").trim();
            let sortSeq = Number(dlt.getCellData(i, "sortSeq") || 9999);

            if (fltrCd1 === String(DsConstants.ODR_CNTR) && fltrCd3 === "1") {
                arr.push({
                    code: code,
                    name: name,
                    sortSeq: sortSeq
                });
            }
        }

        arr.sort(function (a, b) {
            return a.sortSeq - b.sortSeq;
        });

        ds_nextOdrKind.removeAll();

        for (let i = 0; i < arr.length; i++) {
            let row = ds_nextOdrKind.insertRow();
            ds_nextOdrKind.setCellData(row, "code", arr[i].code);
            ds_nextOdrKind.setCellData(row, "name", arr[i].name);
        }

        acb_co_lc_nextOdrKind.setNodeSet("data:ds_nextOdrKind", "name", "code");
        acb_co_lc_nextOdrKind.setValue("");

        if (typeof acb_co_lc_nextOdrKind.refreshItemset === "function") {
            acb_co_lc_nextOdrKind.refreshItemset("replace");
        }
        if (typeof acb_co_lc_nextOdrKind.redraw === "function") {
            acb_co_lc_nextOdrKind.redraw();
        }

    } catch (e) {
        console.log("[NextOdr] error", e);
    }
};

//-------------------------------------------------------------------------
// 재래부두여부 활성/비활성
//-------------------------------------------------------------------------
scwin.setOldPierState = function (lobranCd) {
    lobranCd = (lobranCd || "").trim();

    if (lobranCd === "6AA") {
        acb_lc_oldpireCd.setDisabled(false);
    } else {
        acb_lc_oldpireCd.setValue("");
        acb_lc_oldpireCd.setDisabled(true);
    }
};

//-------------------------------------------------------------------------
// 부두 조회
//-------------------------------------------------------------------------
scwin.f_RetrievePierCd = async function (lobranCd) {
    try {
        console.log("[Pier] start", lobranCd);
        if (!lobranCd) return;

        sbm_piercd.action =
            "/cm.zz.RetrieveComboCMD.do?sysCd=BerthNonUsableEBC&queryId=retriveWrkPlCodeList&param1=" + lobranCd;

        console.log("[Pier] action =", sbm_piercd.action);

        let result = $c.sbm.execute(sbm_piercd);
        console.log("[Pier] execute return =", result);

        await result;

        console.log("[Pier] end");
    } catch (e) {
        console.log("[Pier] error =", e);
    }
};


//-------------------------------------------------------------------------
// 반입CY 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveReturnCy = async function (lobranCd) {
    lobranCd = (lobranCd || "").trim();
    console.log("[ReturnCy] function start", lobranCd);

    // 기존 데이터/선택값 초기화
    ds_returncy.removeAll();
    acb_lc_returnCy.setValue("");

    // action 세팅
    sbm_returncy.action =
        "/cm.zz.RetrieveComboCMD.do?sysCd=ContainerInformationEBC&queryId=retrieveReturnCy&param1=" + lobranCd;

    console.log("[ReturnCy] action =", sbm_returncy.action);

    // 조회 실행
    await $c.sbm.execute(sbm_returncy);


    console.log("[ReturnCy] execute end");
};

//-------------------------------------------------------------------------
// 항차 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveSecond3 = async function () {
    let vsslCd = (ed_cvssl.getValue() || "").trim();

    ds_portcnt.removeAll();
    acb_lc_con_portcnt.setValue("");

    sbm_portcnt.action = "/cm.zz.RetrieveComboCMD.do?sysCd=WorkPlaceEachGoodsEBC&queryId=retrivecPortcntList&param1=" + vsslCd;
    await $c.sbm.execute(sbm_portcnt);
};

//-------------------------------------------------------------------------
// 점소 기준 콤보 재조회
//-------------------------------------------------------------------------
scwin.reloadLobranCombos = async function (lobranCd) {

    lobranCd = (lobranCd || "").trim();

    acb_lc_pierCd.setValue("");
    acb_lc_returnCy.setValue("");
    acb_lc_oldpireCd.setValue("");

    ds_piercd.removeAll();
    ds_returncy.removeAll();

    await scwin.f_RetrievePierCd(lobranCd);

};

scwin.sbm_lobran_submitdone = async function () {

    acb_lc_lobranCd.setValue(scwin.lobranCd);
    scwin.setOldPierState(scwin.lobranCd);

    await scwin.reloadLobranCombos(scwin.lobranCd);

    scwin._isInitLobran = false;

};

scwin.sbm_piercd_submitdone = function () {
    console.log("[Pier submitdone] rowCount =", ds_piercd.getRowCount());

    // 1. dataset 내용을 배열로 꺼냄
    let arr = [];
    for (let i = 0; i < ds_piercd.getRowCount(); i++) {
        arr.push({
            code: String(ds_piercd.getCellData(i, "code") || "").trim(),
            name: String(ds_piercd.getCellData(i, "name") || "").trim()
        });
    }

    // 2. 코드 기준 오름차순 정렬
    arr.sort(function (a, b) {
        return a.code.localeCompare(b.code);
    });

    // 3. dataset 재구성
    ds_piercd.removeAll();

    for (let i = 0; i < arr.length; i++) {
        let rowIdx = ds_piercd.insertRow();
        ds_piercd.setCellData(rowIdx, "code", arr[i].code);
        ds_piercd.setCellData(rowIdx, "name", arr[i].name);
    }

    // 콤보 재바인딩
    acb_lc_pierCd.setNodeSet("data:ds_piercd", "name", "code");
    acb_lc_pierCd.setValue("");

    if (typeof acb_lc_pierCd.refreshItemset === "function") {
        acb_lc_pierCd.refreshItemset("replace");
    }

    let lobranCd = (acb_lc_lobranCd.getValue() || "").trim();
    console.log("[Pier submitdone] lobranCd =", lobranCd);
    scwin.f_RetrieveReturnCy(lobranCd);
    //반입cy콤보
    // sbm_returncy.action = "/cm.zz.RetrieveComboCMD.do?sysCd=ContainerInformationEBC&queryId=retrieveReturnCy&param1=" + acb_lc_lobranCd.getValue();
    // await $c.sbm.execute(sbm_returncy);
};

//초기화
scwin.btn_fieldClear_onclick = async function (e) {
    debugger;
    $c.gus.cfInitObjects(tbl_search, null);
    acb_lc_lobranCd.setValue(scwin.lobranCd);

    await scwin.reloadLobranCombos(scwin.lobranCd);


    scwin.hid_chklineCd = "";
    scwin.hid_chklineNm = "";
    scwin.hid_chkcvssl = "";
    scwin.hid_chkcvsslNm = "";

    ds_portcnt.removeAll();
    acb_lc_con_portcnt.setValue("");
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함. (TO-BE 공통패턴)
// inObj   : 코드/명 입력 컴포넌트
// pairObj : 짝 컴포넌트(코드면 명, 명이면 코드)
// disGubun: 3=LINE, 4=본선
// isCode  : true(코드필드), false(명필드)
//-------------------------------------------------------------------------
scwin.f_chkField = function (inObj, pairObj, disGubun, isCode) {

    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    $c.gus.cfClearPairObj(pairObj);

    var pVal = ($c.gus.cfGetValue(inObj) || "").trim();

    if (!pVal) {
        if (disGubun === 3) {
            scwin.hid_chklineCd = "";
        } else if (disGubun === 4) {
            scwin.hid_chkcvssl = "";
            ds_portcnt.removeAll();
            acb_lc_con_portcnt.setValue("");
        }
        return;
    }

    if (isCode == null || isCode === true) {
        scwin.f_openPopUp(disGubun, pVal, "", "T");
    } else {
        scwin.f_openPopUp(disGubun, "", pVal, "T");
    }
};

//-------------------------------------------------------------------------
// 공통 Popup 처리
// disGubun : 3=LINE, 4=본선
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (disGubun, pCode, pName, pClose) {

    pCode = (pCode || "").trim();
    pName = (pName || "").trim();
    pClose = pClose || "T";

    switch (disGubun) {

        case 3: { // LINE
            udc_comCode_line.setSelectId("retrieveLineInfoList");

            udc_comCode_line.cfCommonPopUp(
                scwin.udc_comCode_line_callBackFunc,
                pCode,
                pName,
                pClose,
                null, null, null, null, null, null, null, null, null, null, null, null, null
            );
            break;
        }

        case 4: { // 본선
            udc_comCode_cvss.setSelectId("retrieveVsslCdInfo");

            udc_comCode_cvss.cfCommonPopUp(
                scwin.udc_comCode_cvss_callBackFunc,
                pCode,
                pName,
                pClose,
                null, null, null, null, null, null, null, null, null, null, null, null, null
            );
            break;
        }

        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 코드 blur 시 공통 Popup 처리
// disGubun : 3=LINE, 4=본선
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUpCode = function (disGubun, codeObj, nameObj, hidVal) {

    let code = (codeObj.getValue() || "").trim();
    let oldCode = (hidVal || "").trim();

    // 이전값과 같으면 아무것도 안 함
    if (code === oldCode) {
        return;
    }

    // 이름 초기화
    if (nameObj) {
        nameObj.setValue("");
    }

    // 코드가 비었으면 clear
    if (code === "") {
        codeObj.setValue("");

        if (disGubun === 3) {
            scwin.hid_chklineCd = "";
        } else if (disGubun === 4) {
            scwin.hid_chkcvssl = "";
            ds_portcnt.removeAll();
            acb_lc_con_portcnt.setValue("");
        }
        return;
    }

    scwin.f_openPopUp(disGubun, code, "", "T");
};

//-------------------------------------------------------------------------
// 이름 변경 시 공통 Popup 처리
// disGubun : 3=LINE, 4=본선
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUpName = function (disGubun, codeObj, nameObj) {

    let name = (nameObj.getValue() || "").trim();

    // 이름이 비면 코드/hidden clear
    if (name === "") {
        nameObj.setValue("");
        codeObj.setValue("");

        if (disGubun === 3) {
            scwin.hid_chklineCd = "";
        } else if (disGubun === 4) {
            scwin.hid_chkcvssl = "";
            ds_portcnt.removeAll();
            acb_lc_con_portcnt.setValue("");
        }
        return;
    }

    // 이름으로 검색
    codeObj.setValue("");
    scwin.f_openPopUp(disGubun, "", name, "T");
};

//-------------------------------------------------------------------------
// 본선 클릭
//-------------------------------------------------------------------------
scwin.udc_comCode_cvss_onclickEvent = function (e) {
    // udc_comCode_cvss.cfCommonPopUp(scwin.udc_comCode_cvss_callBackFunc, ed_cvssl.getValue(), ed_cvsslNm.getValue(), "T", null, null, null, null, null, null, null, null, null, null, null, null, null);
    scwin.f_openCommonPopUp(4, ed_cvssl.getValue(), ed_cvsslNm.getValue(), "F", "T");
};

//-------------------------------------------------------------------------
// 본선 callback
//-------------------------------------------------------------------------
scwin.udc_comCode_cvss_callBackFunc = async function (ret) {

    if (ret != null) {
        if (ret[0] === "N/A") return;

        $c.gus.cfSetReturnValue(ret, ed_cvssl, ed_cvsslNm);
        scwin.hid_chkcvssl = ed_cvssl.getValue();
        scwin.hid_chkcvsslNm = ed_cvsslNm.getValue();

        await scwin.f_RetrieveSecond3();
    } else {
        ed_cvssl.setValue("");
        ed_cvsslNm.setValue("");
        scwin.hid_chkcvssl = "";
        scwin.hid_chkcvsslNm = "";

        ds_portcnt.removeAll();
        acb_lc_con_portcnt.setValue("");
    }
};

//-------------------------------------------------------------------------
// 본선 코드 blur
//-------------------------------------------------------------------------
scwin.udc_comCode_cvss_onblurCodeEvent = function (e) {

    // if (ed_cvssl.getValue() === "") {

    //     ed_cvsslNm.setValue("");
    // }
    scwin.f_chkOpenCommonPopUpEmEdit(ed_cvssl, scwin.hid_chkcvssl, ed_cvsslNm, 4);
};

//-------------------------------------------------------------------------
// 본선 이름 변경
//-------------------------------------------------------------------------
scwin.udc_comCode_cvss_onviewchangeNameEvent = function (info) {

    // if (ed_cvsslNm.getValue() === "") {

    //     ed_cvssl.setValue("");
    // }
    scwin.f_chkOpenCommonPopUpText(ed_cvsslNm, ed_cvssl, 4, scwin.hid_chkcvsslNm);
};

//-------------------------------------------------------------------------
// LINE 클릭
//-------------------------------------------------------------------------
scwin.udc_comCode_line_onclickEvent = function (e) {
    // udc_comCode_line.cfCommonPopUp(scwin.udc_comCode_line_callBackFunc, ed_lineCd.getValue(), ed_lineNm.getValue(), "T", null, null, null, null, null, null, null, null, null, null, null, null, null);
    scwin.f_openCommonPopUp(3, ed_lineCd.getValue(), ed_lineNm.getValue(), "F", "F");
};

//-------------------------------------------------------------------------
// LINE callback
//-------------------------------------------------------------------------
scwin.udc_comCode_line_callBackFunc = function (ret) {
    if (ret != null) {
        if (ret[0] === "N/A") return;

        $c.gus.cfSetReturnValue(ret, ed_lineCd, ed_lineNm);
        scwin.hid_chklineCd = ed_lineCd.getValue();
        scwin.hid_chklineNm = ed_lineNm.getValue();
    } else {
        ed_lineCd.setValue("");
        ed_lineNm.setValue("");
        scwin.hid_chklineCd = "";
        scwin.hid_chklineNm = "";
    }
};

//-------------------------------------------------------------------------
// LINE 코드 blur
//-------------------------------------------------------------------------
scwin.udc_comCode_line_onblurCodeEvent = function (e) {

    // if (ed_lineCd.getValue() === "") {

    //     ed_lineNm.setValue("");
    // }
    scwin.f_chkOpenCommonPopUpEmEdit(ed_lineCd, scwin.hid_chklineCd, ed_lineNm, 3);
};

//-------------------------------------------------------------------------
// LINE 이름 변경
//-------------------------------------------------------------------------
scwin.udc_comCode_line_onviewchangeNameEvent = function (info) {

    // if (ed_lineNm.getValue() === "") {

    //     ed_lineCd.setValue("");
    // }
    scwin.f_chkOpenCommonPopUpText(ed_lineNm, ed_lineCd, 3, scwin.hid_chklineNm);
};

//-------------------------------------------------------------------------
// 이름 입력 후 popup 처리 (AS-IS f_chkOpenCommonPopUpText 대응)
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUpText = function (nameObj, codeObj, disGubun, hidVal) {

    let pCode = "";
    let pName = "";
    let nameVal = (nameObj.getValue() || "").trim();
    let oldVal = (hidVal || "").trim();

    // 이전값과 같으면 팝업 안 띄움
    if (nameVal === oldVal) return;

    // 코드 초기화
    if (codeObj) {
        codeObj.setValue("");
    }

    if (nameVal === "") {
        if (disGubun === 3) {
            scwin.hid_chklineCd = "";
        } else if (disGubun === 4) {
            scwin.hid_chkcvssl = "";
            ds_portcnt.removeAll();
            acb_lc_con_portcnt.setValue("");
        }
        return;
    }

    pName = nameVal;
    scwin.f_openCommonPopUp(disGubun, pCode, pName, "T", "T");
};

//-------------------------------------------------------------------------
// 코드 입력 blur popup 처리 (AS-IS f_chkOpenCommonPopUpEmEdit 대응)
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUpEmEdit = function (codeObj, hidVal, nameObj, disGubun) {

    let pCode = "";
    let pName = "";
    let codeVal = (codeObj.getValue() || "").trim();
    let oldVal = (hidVal || "").trim();

    // 이전값과 같으면 팝업 안 띄움
    if (codeVal === oldVal) return;

    // 이름 초기화
    if (nameObj) {
        nameObj.setValue("");
    }

    // 코드 비어 있으면 clear
    if (codeVal === "") {
        codeObj.setValue("");

        if (disGubun === 3) {
            scwin.hid_chklineCd = "";
        } else if (disGubun === 4) {
            scwin.hid_chkcvssl = "";
            ds_portcnt.removeAll();
            acb_lc_con_portcnt.setValue("");
        }
        return;
    }

    pCode = codeVal;
    scwin.f_openCommonPopUp(disGubun, pCode, pName, "T", "T");
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 호출
// 3=LINE, 4=본선
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {

    pCode = (pCode || "").trim();
    pName = (pName || "").trim();
    pClose = pClose || "T";
    pAllSearch = pAllSearch || "T";

    switch (disGubun) {

        case 3:
            udc_comCode_line.setSelectId("retrieveLineInfoList");
            udc_comCode_line.cfCommonPopUp(
                scwin.udc_comCode_line_callBackFunc,
                pCode,
                pName,
                pClose,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                pAllSearch,
                "LINE,LINE코드,LINE명"
            );
            break;

        case 4:
            udc_comCode_cvss.setSelectId("retrieveVsslCdInfo");
            udc_comCode_cvss.cfCommonPopUp(
                scwin.udc_comCode_cvss_callBackFunc,
                pCode,
                pName,
                pClose,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                pAllSearch,
                "본선,본선코드,본선명"
            );
            break;

        default:
            break;
    }
};

