// scwin.nextArv = function (data) {

//     let odrNo = ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo");
//     let nextOdrNo = ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "nextOdrNo");

//     if (odrNo == nextOdrNo) {
//         return ds_retrieve.setCellData(ds_retrieve.getRowPosition(), "nextOdrNo", "")
//     } else {
//         return ds_retrieve.setCellData(ds_retrieve.getRowPosition(), "nextOdrNo", data)
//     }
// };

scwin.normalizeRetrieveData = function () {
    let rowCnt = ds_retrieve.getRowCount();

    for (let i = 0; i < rowCnt; i++) {
        let odrNo = ds_retrieve.getCellData(i, "odrNo");
        let nextOdrNo = ds_retrieve.getCellData(i, "nextOdrNo");

        if (odrNo === nextOdrNo) {
            ds_retrieve.setCellData(i, "nextOdrNo", "");
            ds_retrieve.setCellData(i, "nextArvWrkPlNm", "");
        }
    }
};

//조회
scwin.btn_retrieve_onclick = function (e) {

    if (!$c.gus.cfValidate([acb_lc_lobranCd])) { // 물류점소
        return;
    }

    dma_condition.set("exceptYn", chb_exceptYn.checked ? "Y" : "N");
    dma_condition.set("lobranCd", acb_lc_lobranCd.getValue());
    dma_condition.set("pier", acb_lc_pierCd.getValue());
    dma_condition.set("oldPier", acb_lc_oldpireCd.getValue());
    dma_condition.set("vsslCd", ed_cvssl.getValue());
    dma_condition.set("vsslNmPortcnt", acb_lc_con_portcnt.getValue());
    dma_condition.set("assgnCls", acb_lc_crryInOutClsCd.getValue());
    dma_condition.set("lineCd", ed_lineCd.getValue());
    dma_condition.set("arrvlportDtFrom", ed_ioDtFrom.getValue());
    dma_condition.set("arrvlportDtTo", ed_ioDtTo.getValue());
    dma_condition.set("odrKnd", acb_co_lc_odrKind.getValue());
    dma_condition.set("nextOdrKnd", acb_co_lc_nextOdrKind.getValue());
    dma_condition.set("fullEmptyClsCd", acb_co_lc_FEkind.getValue());
    dma_condition.set("siz", acb_co_lc_Siz.getValue());
    dma_condition.set("crryinCy", acb_lc_returnCy.getValue());

    $c.sbm.execute(sbm_retrieve);
};

//조회 callback
scwin.sbm_retrieve_submitdone = function () {

    scwin.normalizeRetrieveData();

    let nCnt = ds_retrieve.getRowCount();

    grp_totalCnt.setStyle("display", "");
    total.setValue(nCnt);

    if (nCnt === 0) {
        ed_cnt1.setValue(0);
        ed_cnt2.setValue(0);
        ed_cnt3.setValue(0);
        ed_cnt4.setValue(0);
        ed_cnt5.setValue(0);
        ed_cnt6.setValue(0);
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;
    }

    gr_workImplement.setFocusedCell(0, 0);

    let cnt1 = 0, cnt2 = 0, cnt3 = 0, cnt4 = 0, cnt5 = 0, cnt6 = 0;

    for (let i = 0; i < nCnt; i++) {
        let fe = ds_retrieve.getCellData(i, "fullEmptyClsCd");
        let siz = ds_retrieve.getCellData(i, "cntrSizCd");

        if (fe === "E" && siz === "20") cnt1++;
        else if (fe === "F" && siz === "20") cnt2++;
        else if (fe === "E" && siz === "40") cnt3++;
        else if (fe === "F" && siz === "40") cnt4++;
        else if (fe === "E" && siz === "45") cnt5++;
        else if (fe === "F" && siz === "45") cnt6++;
    }

    ed_cnt1.setValue(cnt1);
    ed_cnt2.setValue(cnt2);
    ed_cnt3.setValue(cnt3);
    ed_cnt4.setValue(cnt4);
    ed_cnt5.setValue(cnt5);
    ed_cnt6.setValue(cnt6);

};

scwin.sbm_portcnt_submitdone = function (e) {
    // if (ds_portcnt.getRowCount() === 0 || ds_portcnt.getCellData(0, "code") !== "") {
    //     ds_portcnt.insertRow(0);
    //     ds_portcnt.setCellData(0, "code", "");
    //     ds_portcnt.setCellData(0, "name", "전체");
    // }
    acb_lc_con_portcnt.setNodeSet("data:ds_portcnt", "name", "code");
    acb_lc_con_portcnt.setValue("");

    if (typeof acb_lc_con_portcnt.refreshItemset === "function") {
        acb_lc_con_portcnt.refreshItemset("replace");
    }
};

scwin.acb_lc_lobranCd_onchange = async function (info) {
    if (scwin._isInitLobran) return;


    let lobranCd = (info && info.newValue != null) ? info.newValue : acb_lc_lobranCd.getValue();
    lobranCd = (lobranCd || "").trim();

    scwin.setOldPierState(lobranCd);
    await scwin.reloadLobranCombos(lobranCd);
};

scwin.sbm_returncy_submitdone = function (e) {

    console.log("[ReturnCy] rowCount =", ds_returncy.getRowCount());

    // 1. dataset -> array
    let arr = [];
    for (let i = 0; i < ds_returncy.getRowCount(); i++) {
        arr.push({
            code: String(ds_returncy.getCellData(i, "code") || "").trim(),
            name: String(ds_returncy.getCellData(i, "name") || "").trim()
        });
    }

    // 2. 코드 기준 오름차순 정렬
    arr.sort(function (a, b) {
        return a.code.localeCompare(b.code);
    });

    // 3. dataset 재구성
    ds_returncy.removeAll();

    for (let i = 0; i < arr.length; i++) {
        let rowIdx = ds_returncy.insertRow();
        ds_returncy.setCellData(rowIdx, "code", arr[i].code);
        ds_returncy.setCellData(rowIdx, "name", arr[i].name);
    }


    // 핵심: itemset을 다시 명시적으로 바인딩
    acb_lc_returnCy.setNodeSet("data:ds_returncy", "name", "code");
    // 선택 초기화
    acb_lc_returnCy.setValue("");

    // 화면 갱신
    if (typeof acb_lc_returnCy.refreshItemset === "function") {
        acb_lc_returnCy.refreshItemset("replace");
    }
};

scwin.sbm_returncy_submiterror = function (e) {
    console.log("[ReturnCy submiterror]", e);
};

scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfAlertMsg("조회 중 오류가 발생했습니다.");
    console.log("[Retrieve submiterror]", e);
};


//엑셀 다운로드 함수
