    var options = {
        fileName: fileName,
        sheetName: sheetName,
        type: "1",
        startRowIndex: 3,          // 4행부터 grid 시작
        useHeader: "true",
        useFooter: "false",
        useSubTotal: "false",
        autoSizeColumn: "true",
